function resolveColorMix(baseToken: string, amount: number, theme: ResolvedTheme): string {
  const base = String(resolveToken(baseToken, theme))
  const alpha = Math.round((amount / 100) * 255)
    .toString(16)
    .padStart(2, "0")
  if (base.startsWith("#") && base.length === 7) return base + alpha
  return base
}

// ─── Declaration resolver ──────────────────────────────────────────────────────

type Declaration =
  | { kind: "static"; prop: string; value: string | number }
  | { kind: "token"; prop: string; token: string }
  | { kind: "tokenWithFallback"; prop: string; token: string; fallback: string | number }
  | { kind: "colorMix"; prop: string; baseToken: string; amount: number }

type StyleRule = {
  id: string
  slot: string
  layer: string
  mode?: "light" | "dark"
  variant?: string
  size?: string
  state?: string
  selectorConditions?: readonly string[]
  declarations: readonly Declaration[]
  source?: { selector: string }
}

function resolveDeclaration(decl: Declaration, theme: ResolvedTheme): [string, string | number] {
  switch (decl.kind) {
    case "static":
      return [decl.prop, decl.value]
    case "token": {
      const v = resolveToken(decl.token, theme)
      return [decl.prop, v]
    }
    case "tokenWithFallback": {
      const v = resolveToken(decl.token, theme)
      return [decl.prop, v === "transparent" ? decl.fallback : v]
    }
    case "colorMix":
      return [decl.prop, resolveColorMix(decl.baseToken, decl.amount, theme)]
  }
}

