export type BadgeNativeSlots = {
  root: ViewStyle
  label: TextStyle
}

export interface BadgeStyleInput {
  variant?: string
  size?: string
  mode?: "light" | "dark"
  state?: {
    pressed?: boolean
    focused?: boolean
    disabled?: boolean
    hovered?: boolean
  }
  dataAttributes?: Record<string, string | undefined>
}

export function resolveBadgeStyles(input: BadgeStyleInput, theme: ResolvedTheme): BadgeNativeSlots {
  const slots: Record<string, Record<string, string | number>> = {}
  for (const slotName of ["root", "label"]) {
    slots[slotName] = {}
  }

  for (const rule of badgeRules) {
    if (rule.mode && rule.mode !== (input.mode ?? "light")) continue
    if (rule.variant && rule.variant !== input.variant) continue
    if (rule.size && rule.size !== input.size) continue
    if (rule.state) {
      const stateActive = input.state?.[rule.state as keyof typeof input.state]
      if (!stateActive) continue
    }
    if (rule.selectorConditions) {
      const allMatch = rule.selectorConditions.every((cond: string) => {
        const m = cond.match(/\[data-([a-z-]+)="([^"]+)"\]/)
        if (!m) return false
        const key = m[1]
        const expected = m[2]
        if (!key || expected === undefined) return false
        return input.dataAttributes?.[key] === expected
      })
      if (!allMatch) continue
    }
    const targetSlot = slots[rule.slot]
    if (!targetSlot) continue
    for (const decl of rule.declarations) {
      const [prop, value] = resolveDeclaration(decl as Declaration, theme)
      targetSlot[prop] = value
    }
  }

  return slots as unknown as BadgeNativeSlots
}

